#include <stdio.h>
#include <string.h>

int main() {
    char s[100001];
    scanf("%s", s);
    int n = strlen(s);
    for (int i = 0; i < n; i++) {
        int min_len = n;
        int start = -1;
        for (int j = i; j < n; j++) {
            char substr[j - i + 2];
            strncpy(substr, s + i, j - i + 1);
            substr[j - i + 1] = '\0';
            int count = 0;
            for (int k = 0; k <= n - (j - i + 1); k++) {
                char temp[j - i + 2];
                strncpy(temp, s + k, j - i + 1);
                temp[j - i + 1] = '\0';
                if (strcmp(substr, temp) == 0) {
                    count++;
                }
            }
            if (count == 1 && j - i + 1 < min_len) {
                min_len = j - i + 1;
                start = i;
            }
        }
        printf("%d %d\n", start + 1, min_len);
    }
    return 0;
}

