import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int n = s.length();
        for (int i = 0; i < n; i++) {
            int min_len = n;
            int start = -1;
            for (int j = i; j < n; j++) {
                String substr = s.substring(i, j + 1);
                int count = 0;
                for (int k = 0; k <= n - (j - i + 1); k++) {
                    String temp = s.substring(k, k + j - i + 1);
                    if (substr.equals(temp)) {
                        count++;
                    }
                }
                if (count == 1 && j - i + 1 < min_len) {
                    min_len = j - i + 1;
                    start = i;
                }
            }
            System.out.println((start + 1) + " " + min_len);
        }
    }
}

